    const form = document.querySelector\('form'\);
    form.addEventListener\('submit', \(e\) => {
      console.log\('FORM SUBMIT EVENT FIRED'\);
    }\);
  }\);

  // Try submitting via JS dispatch
  console.log\('Trying form.requestSubmit\(\)...'\);
  await page.evaluate\(\(\) => {
    const form = document.querySelector\('form'\);
    const btn = form.querySelector\('button[type=\\"submit\\"]'\);
    console.log\('Button tag:', btn?.tagName, 'type:', btn?.type, 'disabled:', btn?.disabled\);
    btn?.click\(\);
  }\);
  await page.waitForTimeout\(3000\);

  // Check if the form button is actually a button
  const btnInfo = await page.evaluate\(\(\) => {
    const btn = document.querySelector\('button[type=\\"submit\\"]'\);
    if \(!btn\) return 'no button found';
    return {
      tag: btn.tagName,
      type: btn.type,
      disabled: btn.disabled,
      form: btn.form ? 'has form' : 'no form',
      text: btn.textContent,
      outerHTML: btn.outerHTML.substring\(0, 300\)
    };
  }\);
  console.log\('Submit button:', JSON.stringify\(btnInfo, null, 2\)\);

  // Try clicking with force
  console.log\('\\\\nClicking with force...'\);
  await page.locator\('button:has-text\(\\"Salvar\\"\)'\).click\({ force: true }\);
